import type {} from "../types/express.d";
import { Request, Response } from "express";
import bcrypt from "bcrypt";
import jwt from "jsonwebtoken";
import { UserModel as User } from "@/infrastructure/database/models/user.model";
import { catchAsync } from "@/interface/middlewares/catchAsync.middleware";
import { ctrlLogger } from "@/infrastructure/logging/controller-logger";
import { tokenBlacklist } from "@/infrastructure/security/token-blacklist.service";
import {
  SystemLogModel,
  ActionType,
} from "@/infrastructure/database/models/system_log.model";
import { UserAgentModel } from "@/infrastructure/database/models/user_agent.model";
import { UserRoleModel } from "@/infrastructure/database/models/user_role.model";
import { RoleModel } from "@/infrastructure/database/models/role.model";
import logger from '@/infrastructure/logging/logger';

/**
 * Helper to fetch all of a user's role names relationally
 */
async function getUserRoles(userId: any): Promise<string[]> {
  const userRoles = await UserRoleModel.find({ user_id: userId }).populate("role_id");
  const roles = userRoles
    .map((ur) => (ur.role_id as any)?.role_name)
    .filter((name) => !!name);

  return roles.length > 0 ? roles : ["student"]; // Default fallback
}

export const register = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('auth.register', req);
  const {
    username,
    password,
    role,
    first_name,
    last_name,
    email,
    phone,
    address,
    identity_card,
  } = req.body;

  log.start({ username });

  const passwordHash = await bcrypt.hash(password, 10);

  const user = await User.create({
    username,
    password: passwordHash,
    first_name,
    last_name,
    email,
    phone,
    address: address || "N/A",
    identity_card: identity_card || "N/A",
  });

  // Assign roles in userroles collection
  if (role) {
    const rolesToAssign = Array.isArray(role) ? role : [role];
    for (const r of rolesToAssign) {
      const roleDoc = await RoleModel.findOne({ role_name: r.toLowerCase() });
      if (roleDoc) {
        await UserRoleModel.create({
          user_id: user._id,
          role_id: roleDoc._id
        });
      }
    }
  }

  log.success(
    res,
    { id: user._id, username: user.username, roles: Array.isArray(role) ? role : [role] },
    "User registered successfully",
  );
});

export const login = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('auth.login', req);
  const { username, password } = req.body;

  log.start({ username });

  const user = await User.findOne({ username });
  if (!user || !(await bcrypt.compare(password, user.password))) {
    return log.fail('invalid_credentials', res, 401, 'Invalid credentials', { username });
  }

  // Fetch agent_id and roles relationally
  const [userAgent, roles] = await Promise.all([
    UserAgentModel.findOne({ user_id: user._id }),
    getUserRoles(user._id)
  ]);

  const agentId = userAgent?.agent_id || null;
  const primaryRole = roles[0];

  const accessToken = jwt.sign(
    { id: user._id, role: primaryRole, roles: roles, agent_id: agentId },
    process.env.JWT_SECRET!,
    { expiresIn: "24h" },
  );

  const refreshToken = jwt.sign(
    { id: user._id },
    process.env.JWT_REFRESH_SECRET!,
    { expiresIn: "7d" },
  );

  // Save refresh token to user
  user.refresh_token = refreshToken;
  await user.save();

  // Cross-domain cookie config: Render (BE) <-> Vercel (FE)
  // SameSite=None + Secure=true is required for cross-site cookies over HTTPS
  const isProduction =
    process.env.RENDER === "true" || process.env.NODE_ENV === "production";
  res.cookie("refreshToken", refreshToken, {
    httpOnly: true,
    secure: isProduction, // true trên Render (HTTPS), false trên localhost
    sameSite: isProduction ? "none" : "lax", // 'none' cho phép cross-domain trên HTTPS
    maxAge: 7 * 24 * 60 * 60 * 1000, // 7 days
  });

  // Log successful login to system audit log (non-critical — fires after response)
  const loginResponse = {
    token: accessToken,
    user: {
      id: user._id,
      username: user.username,
      role: primaryRole,
      roles: roles,
      first_name: user.first_name,
      last_name: user.last_name,
      agent_id: agentId,
    },
  };

  log.success(res, loginResponse, "Login successful");

  try {
    await SystemLogModel.create({
      user_id: user._id,
      title: "Đăng nhập hệ thống",
      action: ActionType.LOGIN,
      entity_type: "AUTH",
      entity_id: user._id.toString(),
      ip_address: req.ip,
      user_agent: req.headers["user-agent"],
    });
  } catch (error) {
    logger.error("Failed to log login:", error);
  }
});

export const refreshToken = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('auth.refresh_token', req);
  const tokenFromCookie = req.cookies.refreshToken;

  log.start({});

  if (!tokenFromCookie) {
    return log.fail('no_refresh_token', res, 401, 'No refresh token provided');
  }

  const user = await User.findOne({ refresh_token: tokenFromCookie });
  if (!user) {
    return log.fail('invalid_refresh_token', res, 403, 'Invalid refresh token');
  }

  try {
    const roles = await getUserRoles(user._id);

    const newAccessToken = jwt.sign(
      { id: user._id, role: roles[0], roles: roles },
      process.env.JWT_SECRET!,
      { expiresIn: "24h" },
    );

    log.success(
      res,
      { token: newAccessToken },
      "Token refreshed successfully",
    );
  } catch (error) {
    log.error('jwt_sign_failed', error);
    return res.statusError("Refresh token expired", 403);
  }
});

export const getMe = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('auth.get_me', req);
  log.start({ userId: req.user.id });

  const user = await User.findById(req.user.id).select("-password");
  if (!user) {
    return log.fail('user_not_found', res, 404, 'User not found');
  }

  // Fetch agent_id and roles
  const [userAgent, roles] = await Promise.all([
    UserAgentModel.findOne({ user_id: user._id }),
    getUserRoles(user._id)
  ]);

  // Normalize user object for frontend
  const userProfile = {
    id: user._id,
    username: user.username,
    role: roles[0],
    roles: roles,
    first_name: user.first_name,
    last_name: user.last_name,
    email: user.email,
    phone: user.phone,
    address: user.address,
    image: user.image,
    bio: (user as any).bio,
    agent_id: userAgent?.agent_id || null,
  };

  log.success(res, userProfile, 'Profile retrieved successfully');
});

export const updateMe = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('auth.update_me', req);
  const { first_name, last_name, email, phone, address, image, bio } = req.body;

  log.start({ userId: req.user.id });

  const user = await User.findById(req.user.id);
  if (!user) {
    return log.fail('user_not_found', res, 404, 'User not found');
  }

  // Update only allowed fields
  if (first_name) user.first_name = first_name;
  if (last_name) user.last_name = last_name;
  if (email) user.email = email;
  if (phone) user.phone = phone;
  if (address) user.address = address;
  if (image) user.image = image;
  if (bio !== undefined) (user as any).bio = bio;

  await user.save();

  const roles = await getUserRoles(user._id);

  const updatedProfile = {
    id: user._id,
    username: user.username,
    role: roles[0],
    roles: roles,
    first_name: user.first_name,
    last_name: user.last_name,
    email: user.email,
    phone: user.phone,
    address: user.address,
    image: user.image,
    bio: (user as any).bio,
  };

  log.success(res, updatedProfile, 'Profile updated successfully');
});

export const changePassword = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('auth.change_password', req);
  const { old_password, new_password } = req.body;

  log.start({ userId: req.user.id });

  const user = await User.findById(req.user.id);
  if (!user) {
    return log.fail('user_not_found', res, 404, 'User not found');
  }

  // Verify old password
  const isMatch = await bcrypt.compare(old_password, user.password);
  if (!isMatch) {
    return log.fail('wrong_old_password', res, 400, 'Mật khẩu cũ không chính xác');
  }

  // Hash new password
  const salt = await bcrypt.genSalt(10);
  user.password = await bcrypt.hash(new_password, salt);

  // Clear refresh token for security (forces re-login)
  user.refresh_token = undefined;

  await user.save();

  log.success(res, null, 'Đổi mật khẩu thành công. Vui lòng đăng nhập lại.');
});

export const logout = catchAsync(async (req: Request, res: Response) => {
  const log = ctrlLogger('auth.logout', req);
  const { refreshToken } = req.cookies;
  const authHeader = req.headers.authorization;

  log.start({});

  // Blacklist the current access token
  if (authHeader && authHeader.startsWith("Bearer ")) {
    const accessToken = authHeader.split(" ")[1];
    tokenBlacklist.add(accessToken);
  }

  if (refreshToken) {
    await User.findOneAndUpdate(
      { refresh_token: refreshToken },
      { refresh_token: null },
    );
  }
  const isProduction =
    process.env.RENDER === "true" || process.env.NODE_ENV === "production";
  res.clearCookie("refreshToken", {
    httpOnly: true,
    secure: isProduction,
    sameSite: isProduction ? "none" : "lax",
  });
  // Log logout to system audit log
  try {
    const user = await User.findOne({ refresh_token: refreshToken });
    if (user) {
      await SystemLogModel.create({
        user_id: user._id,
        action: ActionType.LOGOUT,
        entity_type: "AUTH",
        entity_id: user._id.toString(),
        ip_address: req.ip,
        user_agent: req.headers["user-agent"],
      });
    }
  } catch (error) {
    logger.error("Failed to log logout:", error);
  }

  log.success(res, null, 'Logged out successfully');
});

export const getLoginHistory = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('auth.get_login_history', req);
  log.start({ userId: req.user.id });

  const history = await SystemLogModel.find({
    user_id: req.user.id,
    action: { $in: [ActionType.LOGIN, ActionType.LOGOUT] },
  })
    .sort({ created_at: -1 })
    .limit(10)
    .lean();

  log.success(res, history, 'Login history retrieved successfully', { count: history.length });
});

import { Request, Response, NextFunction } from 'express';

type AsyncHandler = (req: Request, res: Response, next: NextFunction) => Promise<unknown>;

export const catchAsync = (fn: AsyncHandler) => (req: Request, res: Response, next: NextFunction) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

import mongoose, { Schema, Document } from 'mongoose';

export enum UserGender {
  Male = 'male',
  Female = 'female',
  Another = 'another',
}

export enum UserStatus {
  Active = 'active',
  InActive = 'inactive',
  Deleted = 'deleted',
}

export enum UserRole {
  Admin = 'admin',
  Staff = 'staff',
  Teacher = 'teacher',
  Student = 'student',
}

export interface IUser extends Document {
  username: string;
  first_name: string;
  last_name: string;
  email: string;
  phone: string;
  image?: string;
  bio?: string;
  gender: UserGender;
  dob?: Date;
  address: string;
  identity_card: string;
  status: UserStatus;
  // NOTE: 'role' is removed — use UserRoleModel (userroles collection) instead
  password: string;
  refresh_token?: string;
  existing_license_num?: string;
  existing_license_rank?: string;
  created_at: Date;
  updated_at: Date;
}

const UserSchema = new Schema<IUser>({
  username: { type: String, required: true, unique: true },
  first_name: { type: String, required: true },
  last_name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  phone: { type: String, required: true },
  image: { type: String },
  bio: { type: String },
  gender: { type: String, enum: Object.values(UserGender), default: UserGender.Male },
  dob: { type: Date },
  address: { type: String, required: true },
  identity_card: { type: String, required: true },
  status: { type: String, enum: Object.values(UserStatus), default: UserStatus.Active },
  password: { type: String, required: true },
  refresh_token: { type: String },
  existing_license_num: { type: String, default: null },
  existing_license_rank: { type: String, default: null }
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false
});

UserSchema.index({ 
  first_name: 'text', 
  last_name: 'text', 
  phone: 'text', 
  identity_card: 'text' 
}, { 
  name: 'SearchIndex',
  weights: { first_name: 10, last_name: 5, phone: 5, identity_card: 3 }
});
UserSchema.index({ phone: 1 });
UserSchema.index({ identity_card: 1 });
UserSchema.index({ created_at: -1 });

export const UserModel = mongoose.models.Users || mongoose.model<IUser>('Users', UserSchema);
